-- Kelimkar schema restore
CREATE TABLE IF NOT EXISTS public.notifications (
    id smallint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    stankar text NOT NULL,
    message text DEFAULT 'Potřebujeme kelímky!'::text,
    status text DEFAULT '"na cestě", "hotovo"'::text,
    "timestamp" timestamp without time zone DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.profiles (
    id uuid PRIMARY KEY,
    role text NOT NULL,
    name text
);

CREATE TABLE IF NOT EXISTS public.requests (
    id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    stankar text NOT NULL,
    "timestamp" timestamp without time zone DEFAULT now(),
    status text DEFAULT 'čeká'::text
);

CREATE TABLE IF NOT EXISTS public.transactions (
    id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    zamestnanec text DEFAULT '-'::text NOT NULL,
    male_kelimky smallint DEFAULT 0,
    velke_kelimky smallint DEFAULT 0,
    "timestamp" timestamp without time zone DEFAULT (now() AT TIME ZONE 'Europe/Prague'::text),
    status text DEFAULT '''ceka'', ''potvrzeno'''::text,
    stankar text,
    typ_vymeny text DEFAULT 'O+V'::text
);

ALTER TABLE public.notifications ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.requests ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.transactions ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS allow_all ON public.transactions;
CREATE POLICY allow_all ON public.transactions FOR ALL USING (true) WITH CHECK (true);

DROP POLICY IF EXISTS allow_insert_requests ON public.requests;
CREATE POLICY allow_insert_requests ON public.requests FOR INSERT WITH CHECK (true);

DROP POLICY IF EXISTS allow_select_profiles ON public.profiles;
CREATE POLICY allow_select_profiles ON public.profiles FOR SELECT USING (true);

GRANT ALL ON TABLE public.notifications TO anon, authenticated, service_role;
GRANT ALL ON TABLE public.profiles TO anon, authenticated, service_role;
GRANT ALL ON TABLE public.requests TO anon, authenticated, service_role;
GRANT ALL ON TABLE public.transactions TO anon, authenticated, service_role;
GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated, service_role;

